css:
.sig-editorial-hero {
  position: relative;
  width: min(100%, 980px);
  min-height: 440px;
  display: grid;
  grid-template-columns: minmax(0, 1.08fr) minmax(260px, 0.82fr);
  gap: 34px;
  align-items: stretch;
  padding: 42px;
  overflow: hidden;
  border: 1px solid rgba(21,21,21,0.22);
  border-radius: 4px;
  background: linear-gradient(145deg, #fbfaf7, #151515);
  color: #151515;
  box-shadow: 0 28px 64px rgba(21,21,21,0.14);
  font-family: Inter, ui-sans-serif, system-ui, sans-serif;
}
.sig-editorial-hero::before { content: ""; position: absolute; inset: 0; background: linear-gradient(90deg, rgba(21,21,21,0.08) 1px, transparent 1px); background-size: 84px 100%; opacity: 0.78; pointer-events: none; }
.sig-editorial-hero > * { position: relative; z-index: 1; }
.sig-editorial-hero .copy { display: grid; align-content: center; gap: 18px; }
.sig-editorial-hero .kicker { width: fit-content; border: 1px solid rgba(21,21,21,0.22); border-radius: 999px; padding: 6px 10px; color: #b03d2d; background: #151515; font-size: 11px; font-weight: 800; text-transform: uppercase; letter-spacing: 0; }
.sig-editorial-hero h1 { margin: 0; max-width: 620px; font-family: Georgia, Times New Roman, serif; font-size: clamp(40px, 6.4vw, 70px); font-weight: 760; line-height: 0.98; letter-spacing: 0; }
.sig-editorial-hero p { margin: 0; max-width: 560px; color: #6f6b63; font-size: 15px; line-height: 1.78; }
.sig-editorial-hero .actions { display: flex; flex-wrap: wrap; gap: 10px; padding-top: 6px; }
.sig-editorial-hero button { height: 40px; padding: 0 16px; border-radius: calc(4px / 2 + 4px); border: 1px solid rgba(21,21,21,0.22); font: inherit; font-size: 13px; font-weight: 700; cursor: pointer; transition: transform 180ms cubic-bezier(0.16, 1, 0.3, 1), border-color 180ms; }
.sig-editorial-hero .primary { background: #b03d2d; color: #fbfaf7; border-color: #b03d2d; }
.sig-editorial-hero .secondary { background: transparent; color: #151515; }
.sig-editorial-hero button:hover { transform: translateY(-1px); border-color: #b03d2d; }
.sig-editorial-hero .artifact { display: grid; align-content: space-between; gap: 18px; padding: 22px; border: 1px solid rgba(21,21,21,0.22); border-radius: calc(4px - 2px); background: #151515; backdrop-filter: blur(18px) saturate(140%); }
.sig-editorial-hero .artifact h2 { margin: 0; font-size: 13px; color: #b03d2d; text-transform: uppercase; letter-spacing: 0; }
.sig-editorial-hero .metric-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 12px; }
.sig-editorial-hero .metric { padding: 14px; border: 1px solid rgba(21,21,21,0.22); border-radius: calc(4px - 4px); background: color-mix(in srgb, #fbfaf7 76%, transparent); }
.sig-editorial-hero .metric strong { display: block; font-size: 30px; line-height: 1; font-variant-numeric: tabular-nums; }
.sig-editorial-hero .metric span { display: block; margin-top: 6px; color: #6f6b63; font-size: 11px; }
.sig-editorial-hero .rail { height: 9px; border-radius: 999px; background: linear-gradient(90deg, #b03d2d, #151515); }
@media (max-width: 780px) { .sig-editorial-hero { grid-template-columns: 1fr; padding: 28px; } }

.sig-editorial-card { width: min(100%, 390px); padding: 22px; border: 1px solid rgba(21,21,21,0.22); border-radius: 4px; background: #fbfaf7; color: #151515; box-shadow: 0 28px 64px rgba(21,21,21,0.14); font-family: Inter, ui-sans-serif, system-ui, sans-serif; }
.sig-editorial-card .top { display: flex; align-items: start; justify-content: space-between; gap: 16px; margin-bottom: 24px; }
.sig-editorial-card .label { color: #b03d2d; font-size: 12px; font-weight: 800; text-transform: uppercase; letter-spacing: 0; }
.sig-editorial-card .pill { border: 1px solid rgba(21,21,21,0.22); border-radius: 999px; padding: 5px 9px; color: #6f6b63; background: #151515; font-size: 11px; }
.sig-editorial-card h3 { margin: 0 0 10px; font-family: Georgia, Times New Roman, serif; font-size: 32px; line-height: 1; letter-spacing: 0; }
.sig-editorial-card p { margin: 0; color: #6f6b63; font-size: 13px; line-height: 1.7; }
.sig-editorial-card .strip { display: grid; grid-template-columns: 1fr auto; gap: 12px; margin-top: 22px; padding-top: 16px; border-top: 1px solid rgba(21,21,21,0.22); }
.sig-editorial-card .strip strong { font-variant-numeric: tabular-nums; color: #151515; }
.sig-editorial-card .signal { width: 38px; height: 38px; display: grid; place-items: center; border-radius: calc(4px - 4px); background: #b03d2d; color: #fbfaf7; font-weight: 900; }

.sig-editorial-nav { width: min(100%, 900px); min-height: 74px; display: flex; align-items: center; justify-content: space-between; gap: 24px; padding: 14px 16px; border: 1px solid rgba(21,21,21,0.22); border-radius: 4px; background: #fbfaf7; color: #151515; box-shadow: 0 28px 64px rgba(21,21,21,0.14); font-family: Inter, ui-sans-serif, system-ui, sans-serif; }
.sig-editorial-nav .brand { display: flex; align-items: center; gap: 10px; min-width: max-content; font-family: Georgia, Times New Roman, serif; font-size: 15px; font-weight: 800; letter-spacing: 0; }
.sig-editorial-nav .mark { width: 30px; height: 30px; border-radius: calc(4px - 4px); background: linear-gradient(135deg, #b03d2d, #151515); box-shadow: inset 0 0 0 1px rgba(21,21,21,0.22); }
.sig-editorial-nav .links { display: flex; align-items: center; gap: 4px; min-width: 0; overflow-x: auto; }
.sig-editorial-nav a { height: 34px; display: inline-flex; align-items: center; padding: 0 12px; border-radius: calc(4px - 6px); color: #6f6b63; text-decoration: none; font-size: 13px; transition: color 160ms, background 160ms; white-space: nowrap; }
.sig-editorial-nav a:hover, .sig-editorial-nav a.active { color: #151515; background: #151515; }
.sig-editorial-nav button { height: 34px; padding: 0 13px; border-radius: calc(4px - 6px); border: 1px solid #b03d2d; background: #b03d2d; color: #fbfaf7; font: inherit; font-size: 13px; font-weight: 700; cursor: pointer; white-space: nowrap; }
@media (max-width: 720px) { .sig-editorial-nav { align-items: stretch; flex-direction: column; } }

.sig-editorial-form { width: min(100%, 440px); display: grid; gap: 15px; padding: 22px; border: 1px solid rgba(21,21,21,0.22); border-radius: 4px; background: #fbfaf7; color: #151515; box-shadow: 0 28px 64px rgba(21,21,21,0.14); font-family: Inter, ui-sans-serif, system-ui, sans-serif; }
.sig-editorial-form label { display: grid; gap: 7px; font-size: 13px; font-weight: 800; color: #151515; }
.sig-editorial-form small { color: #6f6b63; font-size: 12px; line-height: 1.55; font-weight: 400; }
.sig-editorial-form .row { display: flex; gap: 10px; }
.sig-editorial-form input { min-width: 0; flex: 1; height: 42px; border-radius: calc(4px - 6px); border: 1px solid rgba(21,21,21,0.22); background: #151515; color: #151515; padding: 0 12px; font: inherit; outline: none; transition: border-color 160ms, box-shadow 160ms; }
.sig-editorial-form input:focus { border-color: #b03d2d; box-shadow: 0 0 0 3px color-mix(in srgb, #b03d2d 18%, transparent); }
.sig-editorial-form button { height: 42px; padding: 0 14px; border-radius: calc(4px - 6px); border: 1px solid #b03d2d; background: #b03d2d; color: #fbfaf7; font: inherit; font-size: 13px; font-weight: 800; cursor: pointer; }
@media (max-width: 520px) { .sig-editorial-form .row { flex-direction: column; } }

.sig-editorial-table { width: min(100%, 780px); overflow: hidden; border: 1px solid rgba(21,21,21,0.22); border-radius: 4px; background: #fbfaf7; color: #151515; box-shadow: 0 28px 64px rgba(21,21,21,0.14); font-family: Inter, ui-sans-serif, system-ui, sans-serif; }
.sig-editorial-table table { width: 100%; border-collapse: collapse; font-size: 13px; }
.sig-editorial-table th, .sig-editorial-table td { padding: 12px 14px; text-align: left; border-bottom: 1px solid rgba(21,21,21,0.22); }
.sig-editorial-table th { color: #6f6b63; font-size: 11px; font-weight: 900; text-transform: uppercase; letter-spacing: 0; background: #151515; }
.sig-editorial-table td { color: #151515; }
.sig-editorial-table tr:last-child td { border-bottom: 0; }
.sig-editorial-table tbody tr:hover td { background: #151515; }
.sig-editorial-table .mono { font-variant-numeric: tabular-nums; }
.sig-editorial-table .status { display: inline-flex; align-items: center; gap: 6px; color: #b03d2d; font-weight: 800; }
.sig-editorial-table .status::before { content: ""; width: 7px; height: 7px; border-radius: 50%; background: #b03d2d; }

.btn-ink-spread {
  position: relative;
  padding: 14px 32px;
  background: radial-gradient(circle, #000 0%, #000 50%, transparent 50.1%);
  background-size: 0% 0%;
  background-position: center;
  background-repeat: no-repeat;
  color: #fff;
  font-family: 'Playfair Display', serif;
  font-size: 17px;
  font-style: italic;
  font-weight: 400;
  border: none;
  border-bottom: 1px solid rgba(255,255,255,0.3);
  border-radius: 0;
  cursor: pointer;
  transition: background-size 0.6s cubic-bezier(0.16, 1, 0.3, 1), color 0.3s;
}
.btn-ink-spread:hover {
  background-size: 300% 300%;
  color: #fff;
  border-bottom-color: transparent;
}
.btn-ink-spread:active {
  background-size: 280% 280%;
}

.fx-text-reveal .line {
  overflow: hidden;
  display: block;
}
.fx-text-reveal .line span {
  display: block;
  transform: translateY(110%);
  animation: clip-up 0.7s cubic-bezier(0.16, 1, 0.3, 1) forwards;
}
.fx-text-reveal .line:nth-child(1) span { animation-delay: 0s; }
.fx-text-reveal .line:nth-child(2) span { animation-delay: 0.1s; }
.fx-text-reveal .line:nth-child(3) span { animation-delay: 0.2s; }
@keyframes clip-up {
  to { transform: translateY(0); }
}

.nav-tabs-anim {
  display: flex;
  gap: 24px;
  border-bottom: 0.5px solid #1a1a1a;
  position: relative;
}
.nav-tabs-anim a {
  padding: 10px 0;
  font-family: 'Inter', system-ui;
  font-size: 13px;
  font-weight: 500;
  color: #71717a;
  text-decoration: none;
  transition: color 0.15s;
  position: relative;
}
.nav-tabs-anim a:hover { color: #a1a1aa; }
.nav-tabs-anim a.active { color: #fafafa; }
.nav-tabs-anim a.active::after {
  content: '';
  position: absolute;
  bottom: -0.5px;
  left: 0;
  right: 0;
  height: 2px;
  background: #fafafa;
  border-radius: 1px 1px 0 0;
}

.layout-asym-split {
  display: grid;
  grid-template-columns: 38fr 62fr;
  min-height: 80vh;
  border-top: 0.5px solid #27272a;
}
.layout-asym-split .left {
  padding: 80px 40px 80px 48px;
  border-right: 0.5px solid #27272a;
}
.layout-asym-split .right {
  padding: 80px 48px 80px 40px;
}
@media (max-width: 768px) {
  .layout-asym-split { grid-template-columns: 1fr; }
  .layout-asym-split .left { border-right: none; border-bottom: 0.5px solid #27272a; padding: 40px 24px; }
  .layout-asym-split .right { padding: 40px 24px; }
}

.card-editorial {
  width: 340px;
}
.card-editorial .image {
  aspect-ratio: 3/2;
  background: #e8e4e0;
  margin-bottom: 20px;
}
.card-editorial .category {
  font-family: 'Inter', sans-serif;
  font-size: 10px;
  font-weight: 600;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  color: #a1a1aa;
  margin-bottom: 10px;
}
.card-editorial h3 {
  font-family: 'Playfair Display', serif;
  font-size: 22px;
  font-weight: 700;
  color: #18181b;
  line-height: 1.3;
  margin: 0 0 12px;
}
.card-editorial p {
  font-family: 'Inter', sans-serif;
  font-size: 14px;
  color: #71717a;
  line-height: 1.8;
  margin: 0;
}
